FROM jsonb_to_recordset('[{"id": "cap-107-english-reading-passage-16", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(16-18)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Robert likes to take a walk in the park after work. One day when he was walking\nin the park, he heard a woman calling his name. He stopped to look around, but\ndidn’t see anything   16  . Shortly after Robert saw it, it was gone.\nThough Robert felt a little strange, he did not think about it too much and sat\ndown for a rest on a bench in the park. Then he noticed the snake he had just seen\n17  . Robert was too afraid to move away from the bench. Right at this moment,\na woman behind him shouted, “Come here, Robert. You can’t stay on the bench like\nthat.   18  .”\nIn surprise, Robert turned around and said to the woman, “Excuse me, but that’s\nnot a very nice thing to say, and in fact some people\nsay I’m handsome.”\n“I’m not talking to you,” said the woman. “I’m\ntelling Robert, my pet snake, to get down from the\nbench, not you.”", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(16-18)", "child_qnums": [16, 17, 18]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-19", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(19-21)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "If you cannot live without your car, Zurich might be the last city you would like\nto visit. In Zurich, people are welcome, but cars are not! Over the past 20 years, this\ncity has used smart ways   19  . One is to keep the same total number of parking\nspaces. For example, if 50 new parking spaces are built in one part of the city, then\n50 old spaces in other parts are taken away for other uses. So the total number does\nnot change. Some are unhappy that there are never enough spaces. That is just what\nthe city has in mind: If people find parking more difficult, they will drive less.\n20  , the total number of cars in the city is counted. Over 3,500 little\ncomputers are put under Zurich roads to check the number of cars that enter the city.\nIf the number is higher than the city can deal with, the traffic lights on the roads that\nenter the city will be kept red. So drivers who are traveling into Zurich have to stop\nand wait until there are fewer cars in the city. Now, you may wonder   21  . The\nanswer is simple: The city wants to make more space for its people.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(19-21)", "child_qnums": [19, 20, 21]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-22", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(22-24)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Edward''s Travel Tips\nWhat kind of place do you usually choose to stay for the night during a\ntrip? Expensive hotels that may make you feel like you don’t get what you\npay for? Or cheap hostels that put you and five other strangers in the same\nbedroom? If both choices sound terrible to you, here’s something new: holiday\napartments.\nIn a holiday apartment, you have more space than what a hotel room can\ngive you. Everything in the apartment is at your disposal. The living room,\nthe kitchen, the study, and, of course, the bedrooms are all for your own\nuse. Some apartments even have a lovely garden or a game room. You’ll feel\nat home in the holiday apartment. The best thing is, a holiday apartment is\nnot expensive. The price for a holiday apartment is for two people, and the\napartment is often cheaper than a hotel room for two. You only need to pay a\nlittle more for a third or fourth person. If you travel with friends or your family,\na holiday apartment will be your best choice!\n hostel (提供廉價食宿的)旅舍", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(22-24)", "child_qnums": [22, 23, 24]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-25", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(25-26)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "SHARP WEAR: A T-shirt like no other!\nFirst time here? Don’t worry! Here is our quick lesson for you!\n1. What kind of T-shirt do you like?\n(4 kinds of T-shirts to choose from!)\n2. What color for the T-shirt?\n(We have as many as 16 colors!)\n3. Want a picture on your T-shirt?\nNo, thank you.        Oh yes!\n(Now choose from one of our 72 pictures or send us your own!)\n4. Pocket?       No pocket?\nI don’t need one.             Of course! What kind of pocket then?\n(We’ve got 4 shapes for you!)\n5. How about a different color for the pocket?\nNo, thank you.               Why not?\nSame color as the T-shirt.   (Choose from the 16 colors AGAIN!)\n6. Your size?\n(7 sizes for you!)\n7. How many T-shirts do you want?\n8. Finally, you can pay! ☺", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(25-26)", "child_qnums": [25, 26]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-27", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(27-28)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "The sky is turning bright and clear.\nThe earth is wearing red and green.\nWinter is gone; spring has come.\nThe air smells fresh and sweet.\nThe summer heat is not yet here;\nA little fox comes out to play.\nA bird is busy in a tree\nWaking a daisy from her sleep.\nLittle daisy, little daisy,\nPeople call the flower the “day’s eye.”\nWhen she opens her eye,\nThe springtime brings us cheer.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(27-28)", "child_qnums": [27, 28]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-29", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(29-31)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "When we get wet, we need a towel to get ourselves dry.\nWhen a dog gets wet, all it needs is to shake its body. A study\nin 2010 showed that a wet dog can throw off half the water\non its body by shaking for less than a second. In fact, this\ncommon act of dogs works better than a washing machine.\nThe study found that animal shaking begins with the head\nand ends with the tail. During a shake, the animal’s head, body and skin all move.\nSmaller animals must shake faster than bigger animals to get water off. For example,\nin one second, a rat can shake 18 times, a dog 6 times, and a bear 4 times. Bigger\nanimals can get their bodies dry with fewer shakes.\nFor animals, shaking is not just about getting themselves dry. It is also about\nsaving their lives. Being wet makes animals heavier, and that makes it harder to run.\nIn the animal world, how fast an animal can run often decides whether it will live or\nnot. Maybe that’s why the “wet-dog shake” has become a common habit of many\nanimals.\n skin 皮膚", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(29-31)", "child_qnums": [29, 30, 31]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-32", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(32-34)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Josh: Do you know about “pay it forward coffee” at Flora Café?\nEric: You mean you pay for a cup of coffee for someone poor to have it later?\nJosh: Yeah. A cup of coffee is not much, but on cold winter days like today, it might\nwarm them up a little. And maybe their hearts too.\nEric: But will Flora Café really give this cup of coffee to someone later?\nJosh: Come on. I’ve known the shopkeeper well. He’s an honest man. He’s got a\nblackboard in the shop that says how many cups are paid for and how many\nhave been given out.\nEric: But how will they know who to give? Anyone can ask for it, even if they’re not poor.\nJosh: True, but then I guess they’ll just have to believe in people.\nEric: Perhaps. But will poor people go and ask for a free coffee? Won’t they worry\nabout losing face?\nJosh: Why do you always say things like that?\nEric: Well, it may happen.\nJosh: Yeah, I know, but I still think it’s a good thing to do, and it gets people to care\nabout others.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(32-34)", "child_qnums": [32, 33, 34]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-35", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(35-37)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Over the years, the number of whales has dropped sharply. From 1946\nto 1986, about 340,000 whales were killed. People worry that children in the\nfuture can only see whales in pictures. They believe all kinds of whaling (whale\nhunting) should be stopped before it’s too late.\nSome people are trying to stop whaling all over the world. But they fail\nto notice one fact: Whaling was going on for a long time before the number of\nwhales went down and became a problem.\nWhaling started as early as 1,500 years ago. This was how tribespeople fed\ntheir families. They hunted whales for meat because almost nothing could grow\non their land. They also made whale fat into oil and used it to make candles or\noil lamps. Over the years, whaling became their way of living, and even part of\nwho they are.\nTribe whaling is not the thing we should worry about. Of all the whales that\nwere killed over the past forty years, only 10% were hunted by tribespeople. The\nother 90% died at the hands of the money-making whaling business. When we\ntry to stop all kinds of whaling, we should think what we are asking tribespeople\nto give up and whether this is the best answer to the problem of whaling.\n tribe 部落 fat 脂肪", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(35-37)", "child_qnums": [35, 36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-english-reading-passage-38", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-107-english-reading", "question_type": "reading_passage", "question_text": "(38-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "N B N NEWS\nRyan Kim 7/15/2013\nGuesses about Carolyn Cole have been flying around since last\nweek, and now things have taken a new turn.\nLast week Carolyn Cole won the Inscriber Prize, the country’s\nbiggest book prize, with her book Paper Soldier. Cole herself did not\nshow up for the prize. It was not only the first time in history that a\nfirst-time writer won the prize, but also the first time that the winner did\nnot appear.\nNow here comes another “first time” for the Inscriber: Cole is not\nreal. “She” is in fact Thomas Goode. Goode is known for his picture\nbooks. His best-known book, Blue Moon, won him two national book\nprizes and sold over one million copies.\nGoode had tried to write “serious” books before. His first try was\nParent, which came out in 2006. Sadly, Goode’s big name did not help,\nand there was little interest in Parent. Goode’s friend told NBN that he\nwanted to write a book under a different name. Goode thought that\npeople might treat his book seriously if they did not know it was from a\npicture book writer.\nFor the moment, there has been no word from Goode yet.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "68699662d5b2", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "(38-41)", "child_qnums": [38, 39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
